import React, { useState } from "react";

function ComparePage() {
  const [symbols, setSymbols] = useState("");
  const [data, setData] = useState([]);
  const [loading, setLoading] = useState(false);

  const fetchComparison = async () => {
    if (!symbols.trim()) return alert("Enter at least one symbol");

    setLoading(true);
    try {
      const response = await fetch(
        `http://localhost:3000/api/compare?symbols=${symbols}`
      );
      const result = await response.json();
      setData(result.results || []);
    } catch (err) {
      console.error(err);
      alert("Error fetching stock comparison.");
    }
    setLoading(false);
  };

  return (
    <div style={{ padding: "2rem", fontFamily: "Arial" }}>
      <h2>Stock Comparison</h2>
      <input
        type="text"
        value={symbols}
        onChange={(e) => setSymbols(e.target.value)}
        placeholder="Enter comma-separated stock symbols (e.g., TCS.NS,RELIANCE.NS)"
        style={{ width: "100%", padding: "0.5rem", marginBottom: "1rem" }}
      />
      <button onClick={fetchComparison} disabled={loading}>
        {loading ? "Loading..." : "Compare"}
      </button>

      {data.length > 0 && (
        <table
          style={{
            width: "100%",
            marginTop: "2rem",
            borderCollapse: "collapse",
            border: "1px solid #ccc",
          }}
        >
          <thead>
            <tr style={{ backgroundColor: "#f0f0f0" }}>
              <th>Symbol</th>
              <th>Name</th>
              <th>Price</th>
              <th>PE Ratio</th>
              <th>Market Cap</th>
              <th>Dividend Yield</th>
              <th>52W High</th>
              <th>52W Low</th>
            </tr>
          </thead>
          <tbody>
            {data.map((stock) => (
              <tr key={stock.symbol}>
                <td>{stock.symbol}</td>
                <td>{stock.name}</td>
                <td>{stock.price}</td>
                <td>{stock.pe || "N/A"}</td>
                <td>{(stock.marketCap / 1e9).toFixed(2)} B</td>
                <td>{(stock.dividendYield * 100).toFixed(2)}%</td>
                <td>{stock.fiftyTwoWeekHigh}</td>
                <td>{stock.fiftyTwoWeekLow}</td>
              </tr>
            ))}
          </tbody>
        </table>
      )}
    </div>
  );
}

export default ComparePage;
